  )
}

function Example({
  title,
  children,
  className,
  containerClassName,
  ...props
}: React.ComponentProps<"div"> & {
  title?: string
  containerClassName?: string
}) {
  return (
    <div data-slot="example" className={cn(...containerClassName)} {...props}>
      {title && (
        <div className="px-1.5 py-2 text-xs font-medium text-muted-foreground">
          {title}
        </div>
      )}
      <div data-slot="example-content" className={cn(...)}>
        {children}
      </div>
    </div>
  )
}
```

