## Implementation Plan: Stepper Compound Component

### Architecture Overview

The Stepper has no @base-ui/react primitive that maps to it (there is no `@base-ui/react/stepper`), so it follows the same pattern as `field.tsx` and `card.tsx`: pure semantic HTML with React context, no external primitive. This means both the `base/` and `radix/` registry variants differ only in their internal import paths (`@/registry/bases/base/...` vs `@/registry/bases/radix/...`). The component implementation is identical in logic and structure.

---

### 1. `apps/v4/registry/bases/base/ui/stepper.tsx` — Full Source

```tsx
"use client"

import * as React from "react"
import { cva, type VariantProps } from "class-variance-authority"

import { cn } from "@/registry/bases/base/lib/utils"

// ─── Context ─────────────────────────────────────────────────────────────────

type StepperOrientation = "horizontal" | "vertical"

interface StepperContextValue {
  value: string
  onValueChange: (value: string) => void
  orientation: StepperOrientation
}

const StepperContext = React.createContext<StepperContextValue | null>(null)

function useStepperContext() {
  const ctx = React.useContext(StepperContext)
  if (!ctx) {
    throw new Error(
      "Stepper sub-components must be rendered inside a <Stepper> root."
    )
  }
  return ctx
}

// ─── StepperItem context (per-step) ──────────────────────────────────────────

interface StepperItemContextValue {
  value: string
  disabled: boolean
  isActive: boolean
  isCompleted: boolean
}

const StepperItemContext = React.createContext<StepperItemContextValue | null>(
  null
)

function useStepperItemContext() {
  const ctx = React.useContext(StepperItemContext)
  if (!ctx) {
    throw new Error(
      "StepperTrigger / StepperContent must be rendered inside a <StepperItem>."
    )
  }
  return ctx
}

// ─── Root ─────────────────────────────────────────────────────────────────────

const stepperVariants = cva(
  "cn-stepper group/stepper flex",
  {
    variants: {
      orientation: {
        horizontal:
          "cn-stepper-orientation-horizontal flex-row items-start",
        vertical:
          "cn-stepper-orientation-vertical flex-col",
      },
    },
    defaultVariants: {
      orientation: "horizontal",
    },
  }
)

interface StepperProps
  extends Omit<React.ComponentProps<"div">, "defaultValue">,
    VariantProps<typeof stepperVariants> {
  /** The controlled active step value. */
  value?: string
  /** The default active step value for uncontrolled usage. */
  defaultValue?: string
  /** Called when the active step changes. */
  onValueChange?: (value: string) => void
  orientation?: StepperOrientation
}

function Stepper({
  className,
  orientation = "horizontal",
  value: valueProp,
  defaultValue = "",
  onValueChange,
  ...props
}: StepperProps) {
  const [internalValue, setInternalValue] = React.useState(defaultValue)
  const isControlled = valueProp !== undefined
  const value = isControlled ? valueProp : internalValue

  const handleValueChange = React.useCallback(
    (next: string) => {
      if (!isControlled) {
        setInternalValue(next)
      }
      onValueChange?.(next)
    },
    [isControlled, onValueChange]
  )

  return (
    <StepperContext.Provider
      value={{ value, onValueChange: handleValueChange, orientation }}
    >
      <div
        data-slot="stepper"
        data-orientation={orientation}
        role="tablist"
        aria-orientation={orientation}
        className={cn(stepperVariants({ orientation }), className)}
        {...props}
      />
    </StepperContext.Provider>
  )
}

// ─── StepperItem ──────────────────────────────────────────────────────────────

interface StepperItemProps extends React.ComponentProps<"div"> {
  /** Unique identifier for this step; used as the active value. */
  value: string
  /** When true the step cannot be activated. */
  disabled?: boolean
  /** When true the step is visually marked as completed. */
  completed?: boolean
}

function StepperItem({
  className,
  value,
  disabled = false,
  completed = false,
  ...props
}: StepperItemProps) {
  const { value: activeValue, orientation } = useStepperContext()
  const isActive = activeValue === value
  const isCompleted = completed

  return (
    <StepperItemContext.Provider
      value={{ value, disabled, isActive, isCompleted }}
    >
      <div
        data-slot="stepper-item"
        data-state={isActive ? "active" : isCompleted ? "completed" : "inactive"}
        data-orientation={orientation}
        data-disabled={disabled ? "" : undefined}
        aria-current={isActive ? "step" : undefined}
        className={cn(
          "cn-stepper-item group/stepper-item flex items-center",
          "data-orientation-horizontal:flex-row",
          "data-orientation-vertical:flex-col data-orientation-vertical:items-start",
          className
        )}
        {...props}
      />
    </StepperItemContext.Provider>
  )
}

// ─── StepperTrigger ───────────────────────────────────────────────────────────

function StepperTrigger({
  className,
  children,
  ...props
}: React.ComponentProps<"button">) {
  const { onValueChange } = useStepperContext()
  const { value, disabled, isActive, isCompleted } = useStepperItemContext()

  return (
    <button
      type="button"
      role="tab"
      data-slot="stepper-trigger"
      data-state={isActive ? "active" : isCompleted ? "completed" : "inactive"}
      data-disabled={disabled ? "" : undefined}
      aria-selected={isActive}
      aria-disabled={disabled}
      tabIndex={disabled ? -1 : 0}
      disabled={disabled}
      onClick={() => {
        if (!disabled) {
          onValueChange(value)
        }
      }}
      className={cn(
        "cn-stepper-trigger inline-flex items-center gap-2 outline-none transition-all",
        "focus-visible:ring-[3px] focus-visible:ring-ring/50 focus-visible:outline-1 focus-visible:outline-ring",
        "disabled:pointer-events-none disabled:opacity-50",
        "data-[state=active]:text-foreground",
        "data-[state=inactive]:text-muted-foreground",
        "data-[state=completed]:text-foreground",
        className
      )}
      {...props}
    >
      {children}
    </button>
  )
}

// ─── StepperTitle ─────────────────────────────────────────────────────────────

function StepperTitle({ className, ...props }: React.ComponentProps<"span">) {
  return (
    <span
      data-slot="stepper-title"
      className={cn(
        "cn-stepper-title text-sm font-medium leading-snug",
        className
      )}
      {...props}
    />
  )
}

// ─── StepperDescription ───────────────────────────────────────────────────────

function StepperDescription({
  className,
  ...props
}: React.ComponentProps<"span">) {
  return (
    <span
      data-slot="stepper-description"
      className={cn(
        "cn-stepper-description text-xs text-muted-foreground leading-normal",
        className
      )}
      {...props}
    />
  )
}

// ─── StepperSeparator ─────────────────────────────────────────────────────────

function StepperSeparator({
  className,
  ...props
}: React.ComponentProps<"div">) {
  const { orientation } = useStepperContext()

  return (
    <div
      role="separator"
      data-slot="stepper-separator"
      data-orientation={orientation}
      className={cn(
        "cn-stepper-separator bg-border shrink-0 transition-colors",
        "group-data-horizontal/stepper:h-px group-data-horizontal/stepper:flex-1 group-data-horizontal/stepper:self-start group-data-horizontal/stepper:mt-[calc(theme(spacing.5)_+_1px)]",
        "group-data-vertical/stepper:w-px group-data-vertical/stepper:flex-1 group-data-vertical/stepper:self-stretch group-data-vertical/stepper:ml-[calc(theme(spacing.5)_-_1px)] group-data-vertical/stepper:min-h-4",
        className
      )}
      {...props}
    />
  )
}

// ─── StepperContent ───────────────────────────────────────────────────────────

function StepperContent({
  className,
  ...props
}: React.ComponentProps<"div">) {
  const { isActive } = useStepperItemContext()

  if (!isActive) return null

  return (
    <div
      role="tabpanel"
      data-slot="stepper-content"
      className={cn("cn-stepper-content flex-1 outline-none", className)}
      {...props}
    />
  )
}

// ─── Exports ──────────────────────────────────────────────────────────────────

export {
  Stepper,
  StepperItem,
  StepperTrigger,
  StepperTitle,
  StepperDescription,
  StepperSeparator,
  StepperContent,
  stepperVariants,
}
```

Key design decisions in this source:

- **Controlled/uncontrolled duality**: The `Stepper` root manages `internalValue` state for uncontrolled usage; when `value` prop is provided the component switches to fully controlled mode using `isControlled` guard — identical to how shadcn/ui's existing primitives handle this.
- **Two-level context**: `StepperContext` is shared across the whole tree (current value, orientation, setter). `StepperItemContext` is per-item (its own value, active/completed/disabled state) so child sub-components never need to receive redundant props.
- **`data-slot` / `data-state` / `data-orientation`** attributes mirror the conventions from `tabs.tsx` and `field.tsx` exactly.
- **`role="tablist"` / `role="tab"` / `role="tabpanel"`**: These are the correct ARIA roles for a stepper. `aria-current="step"` on the active `StepperItem` is the WAI-ARIA pattern recommended for steppers (as opposed to `aria-selected` which lives on the trigger button).
- **`StepperContent` uses conditional render** (returns `null` when inactive) instead of `hidden` CSS, matching how `TabsContent` works through the Base UI Panel visibility mechanism.
- **`StepperSeparator` reads orientation from context** so users never need to pass it manually; Tailwind group selectors `group-data-horizontal/stepper:` and `group-data-vertical/stepper:` drive the axis switching.
- **CVA `stepperVariants`** is exported so consumers can extend it.

