"use client"

import * as React from "react"
import { cva, type VariantProps } from "class-variance-authority"

import { cn } from "@/registry/bases/base/lib/utils"

// ─── Root Context ─────────────────────────────────────────────────────────────

type StepperOrientation = "horizontal" | "vertical"

interface StepperContextValue {
  value: string
  onValueChange: (value: string) => void
  orientation: StepperOrientation
}

const StepperContext = React.createContext<StepperContextValue | null>(null)

function useStepperContext(): StepperContextValue {
  const ctx = React.useContext(StepperContext)
  if (!ctx) {
    throw new Error(
      "Stepper sub-components must be rendered inside a <Stepper> root."
    )
  }
  return ctx
}

// ─── Item Context ─────────────────────────────────────────────────────────────

interface StepperItemContextValue {
  value: string
  disabled: boolean
  isActive: boolean
  isCompleted: boolean
}

const StepperItemContext =
  React.createContext<StepperItemContextValue | null>(null)

function useStepperItemContext(): StepperItemContextValue {
  const ctx = React.useContext(StepperItemContext)
  if (!ctx) {
    throw new Error(
      "StepperTrigger and StepperContent must be rendered inside a <StepperItem>."
    )
  }
  return ctx
}

// ─── Stepper (Root) ───────────────────────────────────────────────────────────

const stepperVariants = cva("cn-stepper group/stepper flex", {
  variants: {
    orientation: {
      horizontal: "cn-stepper-orientation-horizontal flex-row items-start",
      vertical: "cn-stepper-orientation-vertical flex-col",
    },
  },
  defaultVariants: {
    orientation: "horizontal",
  },
})

interface StepperProps
  extends Omit<React.ComponentProps<"div">, "defaultValue">,
    VariantProps<typeof stepperVariants> {
  /** The controlled active step value. */
  value?: string
  /** The default active step value for uncontrolled usage. */
  defaultValue?: string
  /** Called when the active step changes. */
  onValueChange?: (value: string) => void
  orientation?: StepperOrientation
}

function Stepper({
  className,
  orientation = "horizontal",
  value: valueProp,
  defaultValue = "",
  onValueChange,
  ...props
}: StepperProps) {
  const [internalValue, setInternalValue] = React.useState(defaultValue)
  const isControlled = valueProp !== undefined
  const value = isControlled ? valueProp : internalValue

  const handleValueChange = React.useCallback(
    (next: string) => {
      if (!isControlled) {
        setInternalValue(next)
      }
      onValueChange?.(next)
    },
    [isControlled, onValueChange]
  )

  return (
    <StepperContext.Provider
      value={{
        value,
        onValueChange: handleValueChange,
        orientation: orientation ?? "horizontal",
      }}
    >
      <div
        data-slot="stepper"
        data-orientation={orientation}
        role="tablist"
        aria-orientation={orientation}
        className={cn(stepperVariants({ orientation }), className)}
        {...props}
      />
    </StepperContext.Provider>
  )
}

// ─── StepperItem ──────────────────────────────────────────────────────────────

interface StepperItemProps extends React.ComponentProps<"div"> {
  /** Unique identifier for this step; used as the active value. */
  value: string
  /** When true the step cannot be activated by clicking. */
  disabled?: boolean
  /** When true the step is visually marked as completed. */
  completed?: boolean
}

function StepperItem({
  className,
  value,
  disabled = false,
  completed = false,
  ...props
}: StepperItemProps) {
  const { value: activeValue, orientation } = useStepperContext()
  const isActive = activeValue === value
  const state = isActive ? "active" : completed ? "completed" : "inactive"

  return (
    <StepperItemContext.Provider
      value={{ value, disabled, isActive, isCompleted: completed }}
    >
      <div
        data-slot="stepper-item"
        data-state={state}
        data-orientation={orientation}
        data-disabled={disabled ? "" : undefined}
        aria-current={isActive ? "step" : undefined}
        className={cn(
          "cn-stepper-item group/stepper-item flex",
          "data-[orientation=horizontal]:flex-row data-[orientation=horizontal]:items-center",
          "data-[orientation=vertical]:flex-col data-[orientation=vertical]:items-start",
          className
        )}
        {...props}
      />
    </StepperItemContext.Provider>
  )
}

// ─── StepperTrigger ───────────────────────────────────────────────────────────

function StepperTrigger({
  className,
  children,
  ...props
}: React.ComponentProps<"button">) {
  const { onValueChange } = useStepperContext()
  const { value, disabled, isActive, isCompleted } = useStepperItemContext()
  const state = isActive ? "active" : isCompleted ? "completed" : "inactive"

  return (
    <button
      type="button"
      role="tab"
      data-slot="stepper-trigger"
      data-state={state}
      data-disabled={disabled ? "" : undefined}
      aria-selected={isActive}
      aria-disabled={disabled}
      tabIndex={disabled ? -1 : 0}
      disabled={disabled}
      onClick={() => {
        if (!disabled) {
          onValueChange(value)
        }
      }}
      className={cn(
        "cn-stepper-trigger inline-flex items-center gap-2 text-left outline-none transition-all",
        "focus-visible:ring-[3px] focus-visible:ring-ring/50 focus-visible:outline-1 focus-visible:outline-ring",
        "disabled:pointer-events-none disabled:opacity-50",
        "data-[state=active]:text-foreground",
        "data-[state=inactive]:text-muted-foreground",
        "data-[state=completed]:text-foreground",
        className
      )}
      {...props}
    >
      {children}
    </button>
  )
}

// ─── StepperTitle ─────────────────────────────────────────────────────────────

function StepperTitle({ className, ...props }: React.ComponentProps<"span">) {
  return (
    <span
      data-slot="stepper-title"
      className={cn(
        "cn-stepper-title text-sm font-medium leading-snug",
        className
      )}
      {...props}
    />
  )
}

// ─── StepperDescription ───────────────────────────────────────────────────────

function StepperDescription({
  className,
  ...props
}: React.ComponentProps<"span">) {
  return (
    <span
      data-slot="stepper-description"
      className={cn(
        "cn-stepper-description text-xs leading-normal text-muted-foreground",
        className
      )}
      {...props}
    />
  )
}

// ─── StepperSeparator ─────────────────────────────────────────────────────────

function StepperSeparator({
  className,
  ...props
}: React.ComponentProps<"div">) {
  const { orientation } = useStepperContext()

  return (
    <div
      role="separator"
      data-slot="stepper-separator"
      data-orientation={orientation}
      className={cn(
        "cn-stepper-separator shrink-0 bg-border transition-colors",
        "group-data-[orientation=horizontal]/stepper:h-px group-data-[orientation=horizontal]/stepper:flex-1 group-data-[orientation=horizontal]/stepper:self-start group-data-[orientation=horizontal]/stepper:mt-5",
        "group-data-[orientation=vertical]/stepper:w-px group-data-[orientation=vertical]/stepper:flex-1 group-data-[orientation=vertical]/stepper:self-stretch group-data-[orientation=vertical]/stepper:ml-5 group-data-[orientation=vertical]/stepper:min-h-4",
        className
      )}
      {...props}
    />
  )
}

// ─── StepperContent ───────────────────────────────────────────────────────────

function StepperContent({
  className,
  ...props
}: React.ComponentProps<"div">) {
  const { isActive } = useStepperItemContext()

  if (!isActive) return null

  return (
    <div
      role="tabpanel"
      data-slot="stepper-content"
      className={cn("cn-stepper-content flex-1 outline-none", className)}
      {...props}
    />
  )
}

// ─── Exports ──────────────────────────────────────────────────────────────────

export {
  Stepper,
  StepperItem,
  StepperTrigger,
  StepperTitle,
  StepperDescription,
  StepperSeparator,
  StepperContent,
  stepperVariants,
}

